mapper.insert:
INSERT INTO archive_comment (
      board_id
    , content
    , writer
    , delete_yn
    , created_date
    , modified_date
) VALUES (
      #{boardId}
    , #{content}
    , #{writer}
    , 0
    , NOW()
    , NULL
)

mapper.update:
UPDATE archive_comment
SET
      modified_date = NOW()
    , content = #{content}
    , writer = #{writer}
WHERE comment_id = #{commentId}

UPDATE archive_comment
SET delete_yn = 1
WHERE comment_id = #{value}

mapper.select:
SELECT

FROM archive_comment
WHERE delete_yn = 0
    AND board_id = #{boardId}
ORDER BY comment_id DESC
LIMIT #{pagination.limitStart}, #{recordSize}
